import json

with open('/tmp/all_tickets.json') as f:
    tickets = json.load(f)

with open('/tmp/all_orders.json') as f:
    orders = json.load(f)

# Count tickets per user
user_ticket_count = {}
for t in tickets:
    uid = t['user_id']
    user_ticket_count[uid] = user_ticket_count.get(uid, 0) + 1

# Sort by ticket count
sorted_users = sorted(user_ticket_count.items(), key=lambda x: -x[1])
print('=== TICKETS PER USER ===')
for uid, count in sorted_users:
    print(f'  {uid}: {count} tickets')

# For each user, find their orders and products
user_products = {}
for o in orders:
    uid = o['user_id']
    if uid in user_ticket_count:
        if uid not in user_products:
            user_products[uid] = []
        user_products[uid].extend(o['product_ids'])

# Count products across all ticket-filing users
product_count = {}
for uid, pids in user_products.items():
    for pid in pids:
        product_count[pid] = product_count.get(pid, 0) + 1

sorted_products = sorted(product_count.items(), key=lambda x: -x[1])
print()
print('=== PRODUCTS BY TICKET-USER ORDERS (top 15) ===')
for pid, count in sorted_products[:15]:
    print(f'  {pid}: {count} orders from ticket users')
"

